// XMLHttpRequest ilə sadə GET sorğusu
const xhr = new XMLHttpRequest();
xhr.open('GET', 'https://jsonplaceholder.typicode.com/posts/1', true);
xhr.onload = function() {
  if (xhr.status === 200) {
    const data = JSON.parse(xhr.responseText);
    console.log('Məlumat:', data);
  } else {
    console.log('Xəta:', xhr.status);
  }
};
xhr.onerror = function() {
  console.log('Şəbəkə xətası');
};
xhr.send();

// XMLHttpRequest ilə POST sorğusu
const xhr = new XMLHttpRequest();
xhr.open('POST', 'https://jsonplaceholder.typicode.com/posts', true);
xhr.setRequestHeader('Content-Type', 'application/json');
const data = JSON.stringify({ title: 'Yeni başlıq', body: 'Məzmun', userId: 1 });
xhr.onload = function() {
  if (xhr.status === 201) {
    const response = JSON.parse(xhr.responseText);
    console.log('Cavab:', response);
  } else {
    console.log('Xəta:', xhr.status);
  }
};
xhr.send(data);

// Hadisə ilə XMLHttpRequest nümunəsi
const button = document.querySelector('#myButton');
button.addEventListener('click', () => {
  const xhr = new XMLHttpRequest();
  xhr.open('GET', 'https://jsonplaceholder.typicode.com/posts/1', true);
  xhr.onload = function() {
    if (xhr.status === 200) {
      const data = JSON.parse(xhr.responseText);
      const container = document.querySelector('#myContainer');
      container.innerText = data.title;
      console.log('Məlumat yükləndi:', data);
    } else {
      console.log('Xəta:', xhr.status);
    }
  };
  xhr.onerror = function() {
    console.log('Şəbəkə xətası');
  };
  xhr.send();
});

